"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[733585],{899313:e=>{e.exports=JSON.parse('{"tag":{"label":"server","permalink":"/dst-api-webdocs/docs/tags/server","allTagsPath":"/dst-api-webdocs/docs/tags","count":37,"items":[{"id":"game-scripts/scenarios/archive_cookpot","title":"Archive Cookpot","description":"Configures the loot table for the archive cookpot chest by defining and adding default items upon chest creation.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/archive_cookpot"},{"id":"game-scripts/prefabs/balloon_held_child","title":"Balloon Held Child","description":"Manages network synchronization and client-side animation of a held balloon prop attached to an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/balloon_held_child"},{"id":"game-scripts/screens/redux/banspopup","title":"Banspopup","description":"Renders a UI popup screen displaying the list of banned players in the current server session.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/banspopup"},{"id":"game-scripts/widgets/bantab","title":"Bantab","description":"Manages the ban list UI tab for managing banned players in the server admin interface, including displaying ban entries, viewing player details, and deleting or clearing bans.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/bantab"},{"id":"game-scripts/widgets/redux/bantab","title":"Bantab","description":"Manages the ban list UI tab in the server admin screen, allowing administrators to view, delete, or clear banned players.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/bantab"},{"id":"game-scripts/screens/redux/caveselectscreen","title":"Caveselectscreen","description":"A UI screen that allows players to select whether caves are enabled for a new server, and transitions to the server creation screen with the chosen setting.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/caveselectscreen"},{"id":"game-scripts/prefabs/chum_aoe","title":"Chum Aoe","description":"Spawns and manages a temporary chum cloud that periodically drops chum pieces and attempts to attract fish schools in ocean areas.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chum_aoe"},{"id":"game-scripts/screens/redux/cloudserversettingspopup","title":"Cloudserversettingspopup","description":"Manages the UI dialog for configuring settings for cloud server creation, including server name, description, password, privacy type, game mode, max players, and clan-specific options.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/cloudserversettingspopup"},{"id":"game-scripts/globalvariableoverrides_pax_server","title":"Globalvariableoverrides Pax Server","description":"Sets global configuration variables for the Pax server environment, including disabling mod warnings and configuring server termination logic.","permalink":"/dst-api-webdocs/docs/game-scripts/globalvariableoverrides_pax_server"},{"id":"game-scripts/screens/redux/hostcloudserverpopup","title":"HostCloudServerPopup","description":"Manages the UI popup shown while requesting and connecting to a cloud server for a festival event.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/hostcloudserverpopup"},{"id":"game-scripts/widgets/intentionpicker","title":"Intentionpicker","description":"A UI widget that lets players select a server intention (Social, Cooperative, Competitive, or Madness) via interactive buttons.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/intentionpicker"},{"id":"game-scripts/widgets/redux/intentionpicker","title":"Intentionpicker","description":"Displays a horizontal picker of server intention options (Social, Cooperative, Competitive, Madness) with description text and callback support.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/intentionpicker"},{"id":"game-scripts/components/inventoryitem_replica","title":"Inventoryitem Replica","description":"Manages network-replicated properties and synchronization of inventory items between server and client, including pickup restrictions, deploy modes, weapon stats, and usage state serialization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/inventoryitem_replica"},{"id":"game-scripts/screens/launchingserverpopup","title":"Launchingserverpopup","description":"Manages the UI popup displayed while the dedicated server is starting or generating a world, providing visual feedback and cancellation support.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/launchingserverpopup"},{"id":"game-scripts/screens/redux/launchingserverpopup","title":"Launchingserverpopup","description":"Manages the UI state and logic while waiting for a dedicated server to start, transition through world generation, and respond to success or failure outcomes.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/launchingserverpopup"},{"id":"game-scripts/components/lunarhailbirdsoundmanager","title":"Lunarhailbirdsoundmanager","description":"Manages audio levels for the lunar hail bird event, controlling ambient sound playback based on event intensity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarhailbirdsoundmanager"},{"id":"game-scripts/screens/redux/manageserverslotscreen","title":"Manageserverslotscreen","description":"Displays a UI screen for managing a specific server save slot, offering options to delete, clone, convert cloud/local storage, or open the save folder.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/manageserverslotscreen"},{"id":"game-scripts/mods","title":"Mods","description":"Manages the lifecycle of mods, including loading, registering prefabs, version checking, and frontend integration.","permalink":"/dst-api-webdocs/docs/game-scripts/mods"},{"id":"game-scripts/networkclientrpc","title":"Networkclientrpc","description":"Manages game-wide RPC (Remote Procedure Call) dispatch, validation, queuing, and rate-limiting for server-bound, client-bound, and shard-bound messages in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/networkclientrpc"},{"id":"game-scripts/networking","title":"Networking","description":"Manages network communication, player synchronization, server operations, and system messaging for Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/networking"},{"id":"game-scripts/widgets/newhostpicker","title":"Newhostpicker","description":"A UI widget for selecting server host behavior (ALONE or TOGETHER mode) in the server creation screen.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/newhostpicker"},{"id":"game-scripts/widgets/redux/newhostpicker","title":"Newhostpicker","description":"Renders a UI selector for choosing host mode (Alone or Together) in the server creation screen.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/newhostpicker"},{"id":"game-scripts/screens/redux/playstyleselectscreen","title":"Playstyleselectscreen","description":"Displays a selection grid of game playstyles for host creation, enabling users to choose a world configuration before proceeding to server or cave setup.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/playstyleselectscreen"},{"id":"game-scripts/screens/quickjoinscreen","title":"Quickjoinscreen","description":"Manages the UI and logic for automatically searching and joining an appropriate multiplayer server based on user-defined preferences and filtering criteria.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/quickjoinscreen"},{"id":"game-scripts/screens/redux/quickjoinscreen","title":"Quickjoinscreen","description":"Manages automated server search and connection logic for quick join functionality in the multiplayer UI.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/quickjoinscreen"},{"id":"game-scripts/prefabs/razor","title":"Razor","description":"A server-side prefab component that provides razor functionality as a combat/shaving tool.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/razor"},{"id":"game-scripts/screens/redux/servercreationscreen","title":"Servercreationscreen","description":"Manages the UI for creating and configuring dedicated or hosted multiplayer servers in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/servercreationscreen"},{"id":"game-scripts/screens/redux/serverlistingscreen","title":"Serverlistingscreen","description":"Manages the server browsing UI, including filtering, sorting, listing, and joining of online and LAN servers with dynamic filter management and server metadata display.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/serverlistingscreen"},{"id":"game-scripts/screens/serverlistingscreen","title":"Serverlistingscreen","description":"A UI screen for browsing, filtering, and joining online or LAN servers in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/serverlistingscreen"},{"id":"game-scripts/serverpreferences","title":"Serverpreferences","description":"Manages server-specific preferences such as name/description filtering and profanity filtering, and persists user data across sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/serverpreferences"},{"id":"game-scripts/widgets/redux/serversaveslot","title":"Serversaveslot","description":"Renders a UI slot representing a saved server world in the server management screens, displaying metadata and enabling navigation or deletion.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/serversaveslot"},{"id":"game-scripts/widgets/redux/serversettingstab","title":"Serversettingstab","description":"Manages the server configuration UI tab in the server creation screen, including server name, description, password, privacy, game mode, player count, and related settings.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/serversettingstab"},{"id":"game-scripts/widgets/serversettingstab","title":"Serversettingstab","description":"Manages the server configuration UI tab for creating and editing dedicated servers in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/serversettingstab"},{"id":"game-scripts/screens/redux/serverslotscreen","title":"Serverslotscreen","description":"Manages the server selection screen UI, displaying existing save slots, filtering/sorting options, and handling user interactions for joining or creating new game instances.","permalink":"/dst-api-webdocs/docs/game-scripts/screens/redux/serverslotscreen"},{"id":"game-scripts/components/shard_players","title":"Shard Players","description":"Tracks and synchronizes the total number of players and ghosts across the local shard and secondary shards in a dedicated server environment.","permalink":"/dst-api-webdocs/docs/game-scripts/components/shard_players"},{"id":"game-scripts/widgets/redux/snapshottab","title":"Snapshottab","description":"Displays and manages server snapshot restoration options in the UI, including listing snapshots and triggering truncation actions.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/snapshottab"},{"id":"game-scripts/prefabs/world_network","title":"World Network","description":"Creates and configures the master network entity for the game world, initializing core systems such as time, seasons, autosave, and client-server synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/world_network"}],"unlisted":false}}')}}]);